#include <stdio.h>
#include <math.h>

int main(void){
    FILE *f = fopen("reconstructed.ppm", "w");
    fprintf(f, "P3\n2400 1800\n255\n");
    const double LN = sqrt(0.56*0.56 + 0.61*0.61 + 0.6*0.6);
    for (int py = 0; py < 1800; py++) {
        for (int px = 0; px < 2400; px++) {
            double fx = px - 1199.5;
            double r, g, b;
            /* sky */
            double fyu = 899.5 - py;
            double ny = fyu / sqrt(fx*fx + fyu*fyu + 810000.0);
            r = 191.491 - 64.014*ny;
            g = 217.090 - 38.409*ny;
            b = 255.0;
            /* checkerboard floor with sphere shadow */
            if (py >= 900) {
                double dy = py - 899.5;
                double tx = floor(fx * 1.5 / dy);
                double tz = floor(1349.0 / dy);
                double c = (((long)(tx + tz)) & 1) == 0 ? 67.0 : 152.0;
                double u = 1.5 * fx / dy;
                double v = 1349.0 / dy;
                double V = 0.4925110581320586*u*u
                         - 0.49426664738523857*u*v
                         + 0.5034854479441354*v*v
                         + 2.9604498793330305*u
                         - 4.503085469490658*v
                         + 9.71510492392345;
                if (V < 0.0) c = floor(c*0.3 + 0.5);
                r = g = b = c;
            }
            /* red sphere with directional shading */
            double sx = fx, sy = py - 993.25;
            if (sx*sx + sy*sy < 184.0*184.0) {
                double nx = sx / 184.0, nyy = sy / 184.0;
                double t = 1.0 - nx*nx - nyy*nyy;
                double nz = t > 0.0 ? sqrt(t) : 0.0;
                double dot = (nx*0.56 + nyy*(-0.61) + nz*(-0.6)) / LN;
                if (dot < 0.0) dot = 0.0;
                double sh = pow(dot, 1.3);
                r = 50.897 + 207.327*sh;
                g = b = 9.966 + 40.890*sh;
            }
            int ri = (int)floor(r + 0.5);
            int gi = (int)floor(g + 0.5);
            int bi = (int)floor(b + 0.5);
            if (ri < 0) ri = 0; if (ri > 255) ri = 255;
            if (gi < 0) gi = 0; if (gi > 255) gi = 255;
            if (bi < 0) bi = 0; if (bi > 255) bi = 255;
            fprintf(f, "%d %d %d\n", ri, gi, bi);
        }
    }
    fclose(f);
    return 0;
}

